def now_iso() -> str:
    return _dt.datetime.now().isoformat(timespec="seconds")


def read_params(path: str | Path) -> dict:
    df = pd.read_csv(path)
    if {"key", "value"}.issubset(df.columns):
        return {str(k).strip(): str(v).strip() for k, v in zip(df["key"], df["value"])}
    if {"param", "value"}.issubset(df.columns):
        return {str(k).strip(): str(v).strip() for k, v in zip(df["param"], df["value"])}
    raise ValueError("params file must contain key,value or param,value columns")


def p_get(params: dict, key: str, default=None, cast=str):
    val = params.get(key, default)
    if val is None:
        return None
    if cast is bool:
        return str(val).strip().lower() in {"1", "true", "yes", "y"}
    if cast is int:
        return int(float(str(val).strip()))
    if cast is float:
        return float(str(val).strip())
    return cast(val)


def ensure_dir(p: str | Path):
    Path(p).mkdir(parents=True, exist_ok=True)


def resolve_path(root: str | Path, p: str | Path) -> Path:
    pp = Path(str(p))
    if pp.is_absolute():
        return pp
    return Path(root) / pp


def write_key_value_csv(path: Path, rows):
    ensure_dir(path.parent)
    with open(path, "w", newline="", encoding="utf-8") as f:
        w = csv.writer(f)
        w.writerow(["key", "value"])
        for k, v in rows:
            w.writerow([k, v])


def write_json(path: Path, obj: dict):
    ensure_dir(path.parent)
    path.write_text(json.dumps(obj, indent=2, ensure_ascii=False), encoding="utf-8")


def emit_embedded_modules(project_root: Path) -> Path:
    """
    Write exact frozen embedded modules to a local runtime scripts directory.
    Existing files are overwritten to guarantee parity with the embedded source.
    """
    scripts_dir = project_root / "_sonar_calc_v1_0_embedded" / "scripts"
    ensure_dir(scripts_dir)
    for filename, payload in EMBEDDED_MODULES.items():
        data = zlib.decompress(base64.b64decode(payload.encode("ascii")))
        (scripts_dir / filename).write_bytes(data)
    if str(scripts_dir) not in sys.path:
        sys.path.insert(0, str(scripts_dir))
    return scripts_dir


def read_panel(panel_path: Path, limit_n: int = 0) -> pd.DataFrame:
    if not panel_path.exists():
        raise FileNotFoundError(f"protein panel not found: {panel_path}")
    df = pd.read_csv(panel_path, keep_default_na=False)
    missing = [c for c in REQUIRED_PANEL_COLUMNS if c not in df.columns]
    if missing:
        raise ValueError(f"protein panel missing columns: {missing}")
    if limit_n and limit_n > 0:
        df = df.head(limit_n).copy()
    return df


