def write_derived_params(project_root: Path, unified: dict) -> dict:
    outdir = project_root / "params" / "_singlefile_generated"
    ensure_dir(outdir)
    paths = {}
    for stage in ["network", "reversible", "destructive", "report"]:
        d = build_stage_params(unified, stage)
        path = outdir / f"params_{stage}.csv"
        write_key_value_csv(path, list(d.items()))
        paths[stage] = path
    return paths


def stage_enabled(params: dict, key: str) -> bool:
    return p_get(params, key, 1, bool)


def should_skip(outdir: Path, expected: str, overwrite: bool) -> bool:
    return (not overwrite) and (outdir / expected).exists()


def network_worker(row_dict: dict, stage_params: dict, project_root_text: str) -> dict:
    import haend_build_network_batch as net
    project_root = Path(project_root_text)
    network_root = resolve_path(project_root, stage_params.get("output_network_dir", "output/networks"))
    ensure_dir(network_root)
    row = pd.Series(row_dict)
    protein_id = str(row_dict["protein_id"])
    outdir = network_root / protein_id
    overwrite = str(stage_params.get("overwrite_network", "0")).lower() in {"1","true","yes"}
    if should_skip(outdir, "network_summary.csv", overwrite):
        try:
            s = pd.read_csv(outdir / "network_summary.csv").iloc[0].to_dict()
            s.update({"protein_id": protein_id, "status": "success", "skipped_existing": 1})
            return s
        except Exception:
            pass
    return net.process_one_protein(row, stage_params, project_root, network_root)


def reversible_worker(row_dict: dict, stage_params: dict, project_root_text: str) -> dict:
    import haend_reversible_batch as rev
    project_root = Path(project_root_text)
    output_root = resolve_path(project_root, stage_params.get("output_root", "output/reversible"))
    protein_id = str(row_dict["protein_id"])
    outdir = output_root / protein_id
    overwrite = str(stage_params.get("overwrite_reversible", "0")).lower() in {"1","true","yes"}
    if should_skip(outdir, "reversible_summary.csv", overwrite):
        try:
            s = pd.read_csv(outdir / "reversible_summary.csv").iloc[0].to_dict()
            s["status"] = "success"
            s["skipped_existing"] = 1
            return s
        except Exception:
            pass
    try:
        return rev.run_one_protein(row_dict, stage_params)
    except Exception as exc:
        return {"protein_id": protein_id, "status": "failed", "error": str(exc), "traceback": traceback.format_exc()}


def destructive_worker(row_dict: dict, stage_params: dict, project_root_text: str) -> dict:
    import haend_destructive_batch as des
    project_root = str(project_root_text)
    protein_id = str(row_dict["protein_id"])
    destructive_root = Path(des.resolve_path(project_root, des.p_get(stage_params, "destructive_output_dir", "output/destructive", str)))
    outdir = destructive_root / protein_id
    overwrite = str(stage_params.get("overwrite_destructive", "0")).lower() in {"1","true","yes"}
    if should_skip(outdir, "destructive_summary.csv", overwrite):
        try:
            s = pd.read_csv(outdir / "destructive_summary.csv").iloc[0].to_dict()
            s["status"] = "success"
            s["skipped_existing"] = 1
            return s
        except Exception:
            pass
    try:
        row = pd.Series(row_dict)
        params = des.build_single_params(stage_params, row, project_root)
        des.ensure_dir(params["output_dir"])
        nodes_df, edges_df, r0, edge_data = des.core.load_nodes_edges(params)
        results = des.core.run_epsilon_sweep(nodes_df, edges_df, r0, edge_data, params)
        single_summary = des.summarize_single(row, nodes_df, edges_df, results)
        des.write_single_outputs(params["output_dir"], params, row, nodes_df, edges_df, results, single_summary)
        single_summary["status"] = "success"
        single_summary["error"] = ""
        return single_summary
    except Exception as exc:
        return {"protein_id": protein_id, "status": "failed", "error": str(exc), "traceback": traceback.format_exc()}


def run_parallel_stage(stage_name, panel, stage_params, project_root, worker, summary_file, failure_file, log_file, n_cpu):
    summary_dir = resolve_path(project_root, stage_params.get("summary_dir", stage_params.get("summary_output_dir", "output/summary")))
    ensure_dir(summary_dir)
    rows = [r.to_dict() for _, r in panel.iterrows()]
    results, failures = [], []
    log_path = summary_dir / log_file
    log_path.write_text(
        f"SONAR-Calc singlefile {stage_name} log\n"
        f"timestamp={now_iso()}\n"
        f"n_jobs={len(rows)}\n"
        f"n_cpu={n_cpu}\n\n",
        encoding="utf-8",
    )
    print(f"\n[STAGE] {stage_name}: jobs={len(rows)}, n_cpu={n_cpu}")
    if n_cpu <= 1:
        for i, row in enumerate(rows, start=1):
            print(f"[{stage_name}] {i}/{len(rows)} {row['protein_id']}")
            res = worker(row, stage_params, str(project_root))
            results.append(res)
            if str(res.get("status","success")) != "success":
                failures.append(res)
    else:
        with ProcessPoolExecutor(max_workers=n_cpu) as ex:
            futs = {ex.submit(worker, row, stage_params, str(project_root)): row for row in rows}
            done = 0
            for fut in as_completed(futs):
                row = futs[fut]
                done += 1
                try:
                    res = fut.result()
                except Exception as exc:
                    res = {"protein_id": str(row.get("protein_id","")), "status": "failed", "error": str(exc), "traceback": traceback.format_exc()}
                results.append(res)
                if str(res.get("status","success")) != "success":
                    failures.append(res)
                if done % 10 == 0 or done == len(rows):
                    print(f"[{stage_name}] completed {done}/{len(rows)}; latest={row.get('protein_id')}; status={res.get('status','success')}")
    summary = pd.DataFrame(results)
    if "protein_id" in summary.columns:
        order = {pid: i for i, pid in enumerate(panel["protein_id"].astype(str).tolist())}
        summary["_order"] = summary["protein_id"].astype(str).map(order)
        summary = summary.sort_values("_order").drop(columns=["_order"])
    failures_df = pd.DataFrame(failures)
    summary.to_csv(summary_dir / summary_file, index=False)
    failures_df.to_csv(summary_dir / failure_file, index=False)
    with open(log_path, "a", encoding="utf-8") as f:
        n_success = int((summary["status"].astype(str) == "success").sum()) if "status" in summary.columns else len(summary)
        f.write(f"finished={now_iso()}\n")
        f.write(f"n_success={n_success}\n")
        f.write(f"n_failed={len(failures_df)}\n")
    print(f"[DONE] {stage_name}: success={len(summary)-len(failures_df)}, failed={len(failures_df)}")


def run_report_builder(project_root: Path, report_params_path: Path, python_exe: str, unified: dict):
    script = project_root / "_sonar_calc_v1_0_embedded" / "scripts" / "build_sonar_report_v1_0.py"
    if not script.exists():
        raise FileNotFoundError(script)

    # The frozen report builder reads summary files from project_root/output/summary.
    # To support single-file custom output locations without modifying report logic,
    # copy the active summary files into that expected default location before report building.
    active_summary_dir = resolve_path(project_root, p_get(unified, "summary_dir", "output/summary", str))
    default_summary_dir = project_root / "output" / "summary"
    ensure_dir(default_summary_dir)
    for fname in [
        "network_panel_summary.csv",
        "reversible_panel_summary.csv",
        "destructive_panel_summary.csv",
        "haend_21protein_integrated_summary.csv",
    ]:
        src = active_summary_dir / fname
        if src.exists():
            shutil.copy2(src, default_summary_dir / fname)

    print("\n[STAGE] report builder")
    cmd = [python_exe, str(script), "--params", str(report_params_path)]
    print(" ".join(cmd))
    proc = subprocess.run(cmd, cwd=str(project_root), text=True)
    if proc.returncode != 0:
        raise RuntimeError(f"Report builder failed with return code {proc.returncode}")


def apply_right_censoring_and_schema(project_root: Path, unified: dict):
    report_dir = resolve_path(project_root, p_get(unified, "report_output_dir", "output/SONAR_report_v1_0", str))
    panel_candidates = [
        report_dir / "SONAR_report_atlas_panel.csv",
        report_dir / "SONAR_report_21protein_panel.csv",
    ]
    panel_path = next((p for p in panel_candidates if p.exists()), None)
    if panel_path is None:
        raise FileNotFoundError(f"No report panel found under {report_dir}")

    df = pd.read_csv(panel_path)

    # Atlas-scale right-censoring report rule for no-damage destructive sweeps.
    for col in EXTENDED_LABEL_FIELDS:
        if col not in df.columns:
            df[col] = np.nan

    cond = (
        df["first_damaging_epsilon_bin"].isna()
        & df["epsilon_max"].notna()
        & df["final_broken_fraction_at_max_epsilon"].fillna(np.nan).notna()
        & (df["final_broken_fraction_at_max_epsilon"].fillna(np.nan).astype(float).abs() < 1e-15)
    )
    if cond.any():
        df.loc[cond, "first_damaging_epsilon_bin"] = df.loc[cond, "epsilon_max"]
        df.loc[cond, "damage_onset_bin_index"] = np.nan
        df.loc[cond, "first_break_contact_type"] = "none_within_range"
        df.loc[cond, "first_break_pair"] = "none_within_range"
        df.loc[cond, "first_break_edge_index"] = np.nan
        df.loc[cond, "sonar_vulnerability_raw"] = df.loc[cond, "sonar_vulnerability_raw"].fillna(0.0)
        df.loc[cond, "sonar_vulnerability_index"] = df.loc[cond, "sonar_vulnerability_index"].fillna(0.0)
        df.loc[cond, "qc_warnings"] = df.loc[cond, "qc_warnings"].fillna("").astype(str) + "; right-censored no damage within scanned epsilon range"
        # Remove the known required-field error if it is the only error.
        if "qc_errors" in df.columns:
            df.loc[cond, "qc_errors"] = (
                df.loc[cond, "qc_errors"].fillna("").astype(str)
                .str.replace("required field missing: first_damaging_epsilon_bin", "", regex=False)
                .str.strip("; ")
            )
            df.loc[cond & (df["qc_errors"].fillna("").astype(str) == ""), "qc_pass"] = True

    # Recompute core response class if absent/unclassified due solely to censoring.
    if "sonar_response_class" in df.columns:
        df.loc[cond & df["sonar_response_class"].fillna("").isin(["", "unclassified"]), "sonar_response_class"] = "right_censored_stable"

    ext = df.reindex(columns=EXTENDED_LABEL_FIELDS)
    core = df.reindex(columns=CORE_REPORT_FIELDS)

    ext_path = report_dir / "SONAR_extended_label_matrix_v1_0.csv"
    core_path = report_dir / "SONAR_core_report_v1_0.csv"
    ext.to_csv(ext_path, index=False)
    core.to_csv(core_path, index=False)

    # Also write schema files.
    pd.DataFrame({"field_order": range(1, len(CORE_REPORT_FIELDS)+1), "field_name": CORE_REPORT_FIELDS}).to_csv(
        report_dir / "SONAR_core_report_schema_v1_0.csv", index=False
    )
    pd.DataFrame({"field_order": range(1, len(EXTENDED_LABEL_FIELDS)+1), "field_name": EXTENDED_LABEL_FIELDS}).to_csv(
        report_dir / "SONAR_extended_label_matrix_schema_v1_0.csv", index=False
    )

    summary = {
        "source_report": str(panel_path),
        "core_report": str(core_path),
        "extended_label_matrix": str(ext_path),
        "n_rows": int(len(df)),
        "n_core_fields": int(len(CORE_REPORT_FIELDS)),
        "n_extended_fields": int(len(EXTENDED_LABEL_FIELDS)),
        "n_right_censored_no_damage": int(cond.sum()),
    }
    write_json(report_dir / "SONAR_singlefile_report_standardization_summary.json", summary)
    print(f"[DONE] standardized report: Core={len(CORE_REPORT_FIELDS)} fields, Extended={len(EXTENDED_LABEL_FIELDS)} fields")
    print(f"       {core_path}")
    print(f"       {ext_path}")


def main():
    ap = argparse.ArgumentParser(description="SONAR-Calc single-file v1.0 runner")
    ap.add_argument("--params", required=True, help="central params CSV")
    args = ap.parse_args()

    unified = read_params(args.params)
    project_root = Path(p_get(unified, "project_root", ".", str)).expanduser().resolve()
    ensure_dir(project_root)
    scripts_dir = emit_embedded_modules(project_root)

    if str(scripts_dir) not in sys.path:
        sys.path.insert(0, str(scripts_dir))

    n_cpu = p_get(unified, "n_cpu", 1, int)
    limit_n = p_get(unified, "limit_n", 0, int)
    python_exe = p_get(unified, "python_executable", sys.executable, str)

    panel_path = resolve_path(project_root, p_get(unified, "protein_panel_file", "protein_panel.csv", str))
    panel = read_panel(panel_path, limit_n=limit_n)

    generated = write_derived_params(project_root, unified)
    summary_dir = resolve_path(project_root, p_get(unified, "summary_dir", "output/summary", str))
    ensure_dir(summary_dir)
    write_json(summary_dir / "sonar_calc_singlefile_manifest.json", {
        "timestamp": now_iso(),
        "project_root": str(project_root),
        "params": str(Path(args.params).resolve()),
        "n_cpu": n_cpu,
        "n_jobs": len(panel),
        "embedded_modules": sorted(EMBEDDED_MODULES.keys()),
        "core_report_fields": len(CORE_REPORT_FIELDS),
        "extended_label_fields": len(EXTENDED_LABEL_FIELDS),
        "derived_params": {k: str(v) for k, v in generated.items()},
    })

    print("=== SONAR-Calc single-file v1.0 ===")
    print(f"project_root={project_root}")
    print(f"panel={panel_path}")
    print(f"n_jobs={len(panel)}")
    print(f"n_cpu={n_cpu}")
    print(f"embedded_scripts={scripts_dir}")

    if stage_enabled(unified, "run_network"):
        params = build_stage_params(unified, "network")
        params["overwrite_network"] = p_get(unified, "overwrite_network", "0", str)
        run_parallel_stage("network", panel, params, project_root, network_worker,
                           "network_panel_summary.csv", "network_panel_failures.csv", "network_batch_run_log.txt", n_cpu)

    if stage_enabled(unified, "run_reversible"):
        params = build_stage_params(unified, "reversible")
        params["overwrite_reversible"] = p_get(unified, "overwrite_reversible", "0", str)
        run_parallel_stage("reversible", panel, params, project_root, reversible_worker,
                           "reversible_panel_summary.csv", "reversible_failures.csv", "reversible_batch_run_log.txt", n_cpu)

    if stage_enabled(unified, "run_destructive"):
        params = build_stage_params(unified, "destructive")
        params["overwrite_destructive"] = p_get(unified, "overwrite_destructive", "0", str)
        run_parallel_stage("destructive", panel, params, project_root, destructive_worker,
                           "destructive_panel_summary.csv", "destructive_failures.csv", "destructive_batch_run_log.txt", n_cpu)

    if stage_enabled(unified, "run_report"):
        run_report_builder(project_root, generated["report"], python_exe, unified)
        apply_right_censoring_and_schema(project_root, unified)

    print("\n=== completed ===")


if __name__ == "__main__":
    main()
